function solve(edges, online, k) {

   const n = online.length;

   // Build adjacency list and in-degree array.

   const adj = new Array(n).fill().map(() => []);

   const inDegree = new Array(n).fill(0);

   for (const [u, v, cost] of edges) {

      adj[u].push({v, cost});

      inDegree[v]++;

   }

   // Compute topological order using Kahn's algorithm.

   const topoOrder = [];

   const queue = [];

   for (let i = 0; i < n; i++) {

      if (inDegree[i] === 0) {

         queue.push(i);

      }

   }

   while (queue.length > 0) {

      const u = queue.shift();

      topoOrder.push(u);

      for (const {v, cost} of adj[u]) {

         inDegree[v]--;

         if (inDegree[v] === 0) {

            queue.push(v);

         }

      }

   }

   // Now, perform binary search.

   // Precompute max edge cost.

   let maxEdge = 0;

   for (const [u, v, cost] of edges) {

      maxEdge = Math.max(maxEdge, cost);

   }

   let low = 0, high = maxEdge;

   let answer = -1;

   while (low <= high) {

      const mid = Math.floor((low + high) / 2);

      if (isValid(mid, topoOrder, adj, online, k)) {

         answer = mid;

         low = mid + 1;

      } else {

         high = mid - 1;

      }

   }

   return answer;

}

