function solve(edges, online, k) {
    const n = online.length;
    const adj = new Array(n).fill().map(() => []);
    const inDegree = new Array(n).fill(0);

    for (const [u, v, cost] of edges) {
        adj[u].push({ v, cost });
        inDegree[v]++;
    }

    const topoOrder = [];
    const queue = [];

    for (let i = 0; i < n; i++) {
        if (inDegree[i] === 0) {
            queue.push(i);
        }
    }

    while (queue.length > 0) {
        const u = queue.shift();
        topoOrder.push(u);
        for (const { v, cost } of adj[u]) {
            inDegree[v]--;
            if (inDegree[v] === 0) {
                queue.push(v);
            }
        }
    }

    let maxEdge = 0;
    for (const [u, v, cost] of edges) {
        maxEdge = Math.max(maxEdge, cost);
    }

    let low = 0, high = maxEdge;
    let answer = -1;

    function isValid(mid) {
        const dp = new Array(n).fill(Infinity);
        dp[0] = 0;

        for (const u of topoOrder) {
            if (!online[u]) continue;
            for (const { v, cost } of adj[u]) {
                if (!online[v]) continue;
                if (cost >= mid) {
                    if (dp[u] + cost < dp[v]) {
                        dp[v] = dp[u] + cost;
                    }
                }
            }
        }

        return dp[n - 1] <= k;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (isValid(mid)) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}
